import pickle


class Payload(object):
    def __reduce__(self):
        return exec, ('import os;os.system("ls")',)


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    return pickle.dumps(payload)

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['GET', 'POST'])
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    # Retrieve YAML data from the request body (POST) or a query parameter 'data' (GET)
    yaml_input = request.data if request.data else request.args.get('data', '')

    if not yaml_input:
        return jsonify({"error": "No YAML data provided"}), 400

    try:
        # Use safe_load to prevent arbitrary code execution (CWE-502)
        # safe_load only parses standard YAML types and avoids executing Python objects
        parsed_data = yaml.safe_load(yaml_input)

        # Ensure the result is a JSON-serializable object
        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML: {str(e)}"}), 400
    except TypeError as e:
        return jsonify({"error": "YAML content must be a serializable structure"}), 400
